package com.example.userservice.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;

import java.util.Collections;
import java.util.Map;

@Service
public class ExternalApiService {

    private final RestClient restClient;

    public ExternalApiService(@Value(\""'${external.api.base-url:https://api.example.com}") String baseUrl) {
        this.restClient = RestClient.builder()
                .baseUrl(baseUrl)
                .build();
    }

    public boolean verifyEmail(String email) {
        try {
            Map result = restClient.get()
                    .uri("/verify/email?email={email}", email)
                    .retrieve()
                    .body(Map.class);
            if (result != null) {
                Object valid = result.get("valid");
                return Boolean.TRUE.equals(valid);
            }
            return false;
        } catch (Exception e) {
            return false;
        }
    }

    public void sendNotification(String userId, String message) {
        try {
            Map<String, String> payload = Map.of(
                "userId", userId,
                "message", message,
                "type", "USER_UPDATE"
            );

            restClient.post()
                    .uri("/notifications")
                    .contentType(MediaType.APPLICATION_JSON)
                    .body(payload)
                    .retrieve()
                    .toBodilessEntity();
        } catch (Exception e) {
            System.err.println("Failed to send notification: " + e.getMessage());
        }
    }

    @SuppressWarnings("unchecked")
    public Map<String, Object> enrichUserProfile(String userId) {
        try {
            Map result = restClient.get()
                    .uri("/users/{userId}/profile", userId)
                    .accept(MediaType.APPLICATION_JSON)
                    .retrieve()
                    .body(Map.class);
            return result != null ? result : Collections.emptyMap();
        } catch (Exception e) {
            return Collections.emptyMap();
        }
    }

    public boolean requestDataDeletion(String userId) {
        try {
            restClient.delete()
                    .uri("/users/{userId}/data", userId)
                    .retrieve()
                    .toBodilessEntity();
            return true;
        } catch (Exception e) {
            return false;
        }
    }
}
